PRAGMA foreign_keys = OFF;
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('36:78', 36, 78, 23, 445, 3783, 'وَضَرَبَ لَنَا مَثَلًا وَّنَسِيَ خَلْقَهٗۗ قَالَ مَنْ يُّحْيِ الْعِظَامَ وَهِيَ رَمِيْمٌ ', 'Dia membuat perumpamaan bagi Kami dan melupakan asal penciptaannya. Dia berkata, “Siapakah yang bisa menghidupkan tulang-belulang yang telah hancur luluh?”645)', '645) Ayat ini terkait dengan kisah al-‘As bin Wa’il yang mendatangi Nabi Muhammad saw. dengan membawa tulang belulang yang sudah hancur, lalu berkata, “Siapakah yang bisa menghidupkan tulang-belulang yang telah hancur luluh ini?”', 'https://everyayah.com/data/Alafasy_128kbps/036078.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('36:79', 36, 79, 23, 445, 3784, 'قُلْ يُحْيِيْهَا الَّذِيْٓ اَنْشَاَهَآ اَوَّلَ مَرَّةٍ ۗوَهُوَ بِكُلِّ خَلْقٍ عَلِيْمٌ ۙ', 'Katakanlah (Nabi Muhammad), “Yang akan menghidupkannya adalah Zat yang menciptakannya pertama kali. Dia Maha Mengetahui setiap makhluk.', '', 'https://everyayah.com/data/Alafasy_128kbps/036079.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('36:80', 36, 80, 23, 445, 3785, ' ۨالَّذِيْ جَعَلَ لَكُمْ مِّنَ الشَّجَرِ الْاَخْضَرِ نَارًاۙ فَاِذَآ اَنْتُمْ مِّنْهُ تُوْقِدُوْنَ ', '(Dialah) yang menjadikan api untukmu dari kayu yang hijau. Kemudian, seketika itu kamu menyalakan (api) darinya.”', '', 'https://everyayah.com/data/Alafasy_128kbps/036080.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('36:81', 36, 81, 23, 445, 3786, 'اَوَلَيْسَ الَّذِيْ خَلَقَ السَّمٰوٰتِ وَالْاَرْضَ بِقٰدِرٍ عَلٰٓى اَنْ يَّخْلُقَ مِثْلَهُمْ ۗبَلٰى وَهُوَ الْخَلّٰقُ الْعَلِيْمُ ', 'Bukankah Zat yang menciptakan langit dan bumi mampu menciptakan manusia yang serupa mereka itu (di akhirat kelak)? Benar. Dialah yang Maha Banyak Mencipta lagi Maha Mengetahui.', '', 'https://everyayah.com/data/Alafasy_128kbps/036081.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('36:82', 36, 82, 23, 445, 3787, 'اِنَّمَآ اَمْرُهٗٓ اِذَآ اَرَادَ شَيْـًٔاۖ اَنْ يَّقُوْلَ لَهٗ كُنْ فَيَكُوْنُ ', 'Sesungguhnya ketetapan-Nya, jika Dia menghendaki sesuatu, Dia hanya berkata kepadanya, “Jadilah!” Maka, jadilah (sesuatu) itu.', '', 'https://everyayah.com/data/Alafasy_128kbps/036082.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('36:83', 36, 83, 23, 445, 3788, 'فَسُبْحٰنَ الَّذِيْ بِيَدِهٖ مَلَكُوْتُ كُلِّ شَيْءٍ وَّاِلَيْهِ تُرْجَعُوْنَ ࣖ', 'Maka, Maha Suci (Allah) yang di tangan-Nya kekuasaan atas segala sesuatu dan kepada-Nya kamu dikembalikan.', '', 'https://everyayah.com/data/Alafasy_128kbps/036083.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:1', 37, 1, 23, 446, 3789, 'وَالصّٰۤفّٰتِ صَفًّاۙ', 'Demi (rombongan malaikat) yang berbaris bersaf-saf, (untuk beribadah kepada Allah),', '', 'https://everyayah.com/data/Alafasy_128kbps/037001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:2', 37, 2, 23, 446, 3790, 'فَالزّٰجِرٰتِ زَجْرًاۙ', 'demi (rombongan malaikat) yang mencegah (segala sesuatu) dengan sungguh-sungguh,', '', 'https://everyayah.com/data/Alafasy_128kbps/037002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:3', 37, 3, 23, 446, 3791, 'فَالتّٰلِيٰتِ ذِكْرًاۙ', 'demi (rombongan malaikat) yang membacakan peringatan,', '', 'https://everyayah.com/data/Alafasy_128kbps/037003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:4', 37, 4, 23, 446, 3792, 'اِنَّ اِلٰهَكُمْ لَوَاحِدٌۗ ', 'sungguh, Tuhanmu benar-benar Esa.', '', 'https://everyayah.com/data/Alafasy_128kbps/037004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:5', 37, 5, 23, 446, 3793, 'رَبُّ السَّمٰوٰتِ وَالْاَرْضِ وَمَا بَيْنَهُمَا وَرَبُّ الْمَشَارِقِۗ ', 'Tuhan langit dan bumi dan apa yang berada di antara keduanya dan Tuhan tempat-tempat terbitnya matahari.', '', 'https://everyayah.com/data/Alafasy_128kbps/037005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:6', 37, 6, 23, 446, 3794, 'اِنَّا زَيَّنَّا السَّمَاۤءَ الدُّنْيَا بِزِيْنَةِ ِۨالْكَوَاكِبِۙ', 'Sesungguhnya Kami telah menghiasi langit dunia (yang terdekat) dengan hiasan (berupa) bintang-bintang.', '', 'https://everyayah.com/data/Alafasy_128kbps/037006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:7', 37, 7, 23, 446, 3795, 'وَحِفْظًا مِّنْ كُلِّ شَيْطٰنٍ مَّارِدٍۚ ', '(Kami telah menjaganya dengan) penjagaan yang sempurna dari setiap setan yang durhaka.', '', 'https://everyayah.com/data/Alafasy_128kbps/037007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:8', 37, 8, 23, 446, 3796, 'لَا يَسَّمَّعُوْنَ اِلَى الْمَلَاِ الْاَعْلٰى وَيُقْذَفُوْنَ مِنْ كُلِّ جَانِبٍۖ ', 'Mereka (setan-setan) tidak dapat mendengar (percakapan) para malaikat dan mereka dilempari dari segala penjuru', '', 'https://everyayah.com/data/Alafasy_128kbps/037008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:9', 37, 9, 23, 446, 3797, 'دُحُوْرًا وَّلَهُمْ عَذَابٌ وَّاصِبٌ ', 'untuk mengusir mereka. Bagi mereka azab yang kekal (di akhirat),', '', 'https://everyayah.com/data/Alafasy_128kbps/037009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:10', 37, 10, 23, 446, 3798, 'اِلَّا مَنْ خَطِفَ الْخَطْفَةَ فَاَتْبَعَهٗ شِهَابٌ ثَاقِبٌ ', 'kecuali (setan) yang menyambar pembicaraan dengan sekali sambar; maka ia dikejar oleh bintang yang menyala.', '', 'https://everyayah.com/data/Alafasy_128kbps/037010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:11', 37, 11, 23, 446, 3799, 'فَاسْتَفْتِهِمْ اَهُمْ اَشَدُّ خَلْقًا اَمْ مَّنْ خَلَقْنَا ۗاِنَّا خَلَقْنٰهُمْ مِّنْ طِيْنٍ لَّازِبٍ ', 'Maka, tanyakanlah kepada mereka (musyrik Makkah), “Apakah mereka (manusia) lebih sulit penciptaannya ataukah selainnya (langit, bumi, dan lainnya) yang telah Kami ciptakan?” Sesungguhnya Kami telah menciptakan (bapak) mereka (Adam) dari tanah liat.', '', 'https://everyayah.com/data/Alafasy_128kbps/037011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:12', 37, 12, 23, 446, 3800, 'بَلْ عَجِبْتَ وَيَسْخَرُوْنَ ۖ ', 'Bahkan, engkau (Nabi Muhammad) menjadi heran (terhadap keingkaran mereka) dan mereka selalu menghinamu.', '', 'https://everyayah.com/data/Alafasy_128kbps/037012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:13', 37, 13, 23, 446, 3801, 'وَاِذَا ذُكِّرُوْا لَا يَذْكُرُوْنَ ۖ ', 'Apabila diberi peringatan, mereka tidak mengingat (mengindahkannya).', '', 'https://everyayah.com/data/Alafasy_128kbps/037013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:14', 37, 14, 23, 446, 3802, 'وَاِذَا رَاَوْا اٰيَةً يَّسْتَسْخِرُوْنَۖ ', 'Apabila melihat suatu tanda (kebesaran Allah atau kebenaran Nabi Muhammad), mereka sangat menghina.', '', 'https://everyayah.com/data/Alafasy_128kbps/037014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:15', 37, 15, 23, 446, 3803, 'وَقَالُوْٓا اِنْ هٰذَآ اِلَّا سِحْرٌ مُّبِيْنٌ ۚ ', 'Mereka berkata, “Ini tidak lain hanyalah sihir yang nyata.', '', 'https://everyayah.com/data/Alafasy_128kbps/037015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:16', 37, 16, 23, 446, 3804, 'ءَاِذَا مِتْنَا وَكُنَّا تُرَابًا وَّعِظَامًا ءَاِنَّا لَمَبْعُوْثُوْنَۙ', 'Apabila kami telah mati, (lalu) menjadi tanah dan tulang-belulang, apakah kami benar-benar akan dibangkitkan?', '', 'https://everyayah.com/data/Alafasy_128kbps/037016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:17', 37, 17, 23, 446, 3805, 'اَوَاٰبَاۤؤُنَا الْاَوَّلُوْنَۗ ', 'Apakah nenek moyang kami yang terdahulu (akan dibangkitkan pula)?”', '', 'https://everyayah.com/data/Alafasy_128kbps/037017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:18', 37, 18, 23, 446, 3806, 'قُلْ نَعَمْ وَاَنْتُمْ دٰخِرُوْنَۚ ', 'Katakanlah (Nabi Muhammad), “Ya (kamu akan dibangkitkan) dan kamu akan terhina.”', '', 'https://everyayah.com/data/Alafasy_128kbps/037018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:19', 37, 19, 23, 446, 3807, 'فَاِنَّمَا هِيَ زَجْرَةٌ وَّاحِدَةٌ فَاِذَا هُمْ يَنْظُرُوْنَ ', 'Sesungguhnya kebangkitan itu hanya dengan satu teriakan (tiupan sangkakala kedua). Maka, seketika itu mereka (bangun dari kematiannya) melihat (apa yang terjadi).', '', 'https://everyayah.com/data/Alafasy_128kbps/037019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:20', 37, 20, 23, 446, 3808, 'وَقَالُوْا يٰوَيْلَنَا هٰذَا يَوْمُ الدِّيْنِ ', 'Mereka berkata, “Alangkah celaka kami! (Kiranya) inilah hari Pembalasan itu.”', '', 'https://everyayah.com/data/Alafasy_128kbps/037020.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:21', 37, 21, 23, 446, 3809, 'هٰذَا يَوْمُ الْفَصْلِ الَّذِيْ كُنْتُمْ بِهٖ تُكَذِّبُوْنَ ࣖ', 'Inilah hari keputusan yang dahulu (selalu) kamu dustakan.', '', 'https://everyayah.com/data/Alafasy_128kbps/037021.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:22', 37, 22, 23, 446, 3810, 'اُحْشُرُوا الَّذِيْنَ ظَلَمُوْا وَاَزْوَاجَهُمْ وَمَا كَانُوْا يَعْبُدُوْنَ ۙ', '(Lalu, diperintahkan kepada para malaikat,) “Kumpulkanlah orang-orang yang zalim beserta teman sejawat mereka dan apa yang dahulu mereka sembah', '', 'https://everyayah.com/data/Alafasy_128kbps/037022.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:23', 37, 23, 23, 446, 3811, 'مِنْ دُوْنِ اللّٰهِ فَاهْدُوْهُمْ اِلٰى صِرَاطِ الْجَحِيْمِ ', 'selain Allah. Lalu, tunjukkanlah kepada mereka jalan ke (neraka) Jahim.', '', 'https://everyayah.com/data/Alafasy_128kbps/037023.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:24', 37, 24, 23, 446, 3812, 'وَقِفُوْهُمْ اِنَّهُمْ مَّسْـُٔوْلُوْنَ ۙ', 'Tahanlah mereka (di tempat perhentian). Sesungguhnya mereka akan ditanya (tentang keyakinan dan perilaku mereka).”', '', 'https://everyayah.com/data/Alafasy_128kbps/037024.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:25', 37, 25, 23, 447, 3813, 'مَا لَكُمْ لَا تَنَاصَرُوْنَ ', '(Mereka lalu dikecam,) “Mengapa kamu tidak tolong-menolong (sebagaimana kamu di dunia)?”', '', 'https://everyayah.com/data/Alafasy_128kbps/037025.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:26', 37, 26, 23, 447, 3814, 'بَلْ هُمُ الْيَوْمَ مُسْتَسْلِمُوْنَ', 'Bahkan, mereka pada hari itu menyerah (kepada putusan Allah).', '', 'https://everyayah.com/data/Alafasy_128kbps/037026.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:27', 37, 27, 23, 447, 3815, 'وَاَقْبَلَ بَعْضُهُمْ عَلٰى بَعْضٍ يَّتَسَاۤءَلُوْنَ ', 'Sebagian mereka menghadap kepada sebagian yang lain saling bertanya (berbantah-bantahan).', '', 'https://everyayah.com/data/Alafasy_128kbps/037027.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:28', 37, 28, 23, 447, 3816, 'قَالُوْٓا اِنَّكُمْ كُنْتُمْ تَأْتُوْنَنَا عَنِ الْيَمِيْنِ ', '(Pengikut) mereka berkata (kepada pemimpinnya), “Sesungguhnya kamulah yang dahulu selalu mendatangi kami dari arah kanan (untuk menghalangi kami dari kebajikan).”', '', 'https://everyayah.com/data/Alafasy_128kbps/037028.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:29', 37, 29, 23, 447, 3817, 'قَالُوْا بَلْ لَّمْ تَكُوْنُوْا مُؤْمِنِيْنَۚ ', '(Pemimpin) mereka menjawab, “(Tidak,) bahkan kamulah yang tidak (mau) menjadi orang mukmin.', '', 'https://everyayah.com/data/Alafasy_128kbps/037029.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:30', 37, 30, 23, 447, 3818, 'وَمَا كَانَ لَنَا عَلَيْكُمْ مِّنْ سُلْطٰنٍۚ بَلْ كُنْتُمْ قَوْمًا طٰغِيْنَ ', '(Sebenarnya,) kami sedikit pun tidak berkuasa terhadapmu (untuk menghalang-halangimu), bahkan kamulah kaum yang melampaui batas.', '', 'https://everyayah.com/data/Alafasy_128kbps/037030.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:31', 37, 31, 23, 447, 3819, 'فَحَقَّ عَلَيْنَا قَوْلُ رَبِّنَآ  ۖاِنَّا لَذَاۤىِٕقُوْنَ ', 'Maka, putusan (azab) Tuhan (akan) benar-benar menimpa kita. Pasti kita akan merasakan (azab itu).', '', 'https://everyayah.com/data/Alafasy_128kbps/037031.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:32', 37, 32, 23, 447, 3820, 'فَاَغْوَيْنٰكُمْ اِنَّا كُنَّا غٰوِيْنَ ', 'Kami (mengakui) telah menyesatkan kamu. Sesungguhnya kami sendiri orang-orang yang sesat.”', '', 'https://everyayah.com/data/Alafasy_128kbps/037032.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:33', 37, 33, 23, 447, 3821, 'فَاِنَّهُمْ يَوْمَىِٕذٍ فِى الْعَذَابِ مُشْتَرِكُوْنَ', 'Sesungguhnya mereka pada hari itu bersama-sama merasakan azab.', '', 'https://everyayah.com/data/Alafasy_128kbps/037033.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:34', 37, 34, 23, 447, 3822, 'اِنَّا كَذٰلِكَ نَفْعَلُ بِالْمُجْرِمِيْنَ', 'Sesungguhnya demikianlah Kami memperlakukan orang-orang yang berbuat dosa.', '', 'https://everyayah.com/data/Alafasy_128kbps/037034.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:35', 37, 35, 23, 447, 3823, 'اِنَّهُمْ كَانُوْٓا اِذَا قِيْلَ لَهُمْ لَآ اِلٰهَ اِلَّا اللّٰهُ يَسْتَكْبِرُوْنَ ۙ', 'Sesungguhnya dahulu apabila dikatakan kepada mereka, “Lā ilāha illallāh” (Tidak ada tuhan selain Allah), mereka menyombongkan diri.', '', 'https://everyayah.com/data/Alafasy_128kbps/037035.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:36', 37, 36, 23, 447, 3824, 'وَيَقُوْلُوْنَ اَىِٕنَّا لَتَارِكُوْٓا اٰلِهَتِنَا لِشَاعِرٍ مَّجْنُوْنٍ ۗ ', 'Mereka berkata, “Apakah kami harus meninggalkan sesembahan kami karena seorang penyair gila?”', '', 'https://everyayah.com/data/Alafasy_128kbps/037036.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:37', 37, 37, 23, 447, 3825, 'بَلْ جَاۤءَ بِالْحَقِّ وَصَدَّقَ الْمُرْسَلِيْنَ', 'Padahal dia (Nabi Muhammad) datang dengan membawa kebenaran dan membenarkan para rasul (sebelumnya).', '', 'https://everyayah.com/data/Alafasy_128kbps/037037.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:38', 37, 38, 23, 447, 3826, 'اِنَّكُمْ لَذَاۤىِٕقُوا الْعَذَابِ الْاَلِيْمِ ۚ ', 'Sesungguhnya kamu pasti akan merasakan azab yang pedih.', '', 'https://everyayah.com/data/Alafasy_128kbps/037038.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:39', 37, 39, 23, 447, 3827, 'وَمَا تُجْزَوْنَ اِلَّا مَا كُنْتُمْ تَعْمَلُوْنَۙ', 'Kamu tidak diberi balasan, kecuali terhadap apa yang telah kamu kerjakan.', '', 'https://everyayah.com/data/Alafasy_128kbps/037039.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:40', 37, 40, 23, 447, 3828, 'اِلَّا عِبَادَ اللّٰهِ الْمُخْلَصِيْنَ ', 'Akan tetapi, hamba-hamba Allah yang terpilih (karena keikhlasannya),', '', 'https://everyayah.com/data/Alafasy_128kbps/037040.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:41', 37, 41, 23, 447, 3829, 'اُولٰۤىِٕكَ لَهُمْ رِزْقٌ مَّعْلُوْمٌۙ', 'mereka itu memperoleh rezeki yang sudah ditentukan,', '', 'https://everyayah.com/data/Alafasy_128kbps/037041.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:42', 37, 42, 23, 447, 3830, 'فَوَاكِهُ ۚوَهُمْ مُّكْرَمُوْنَۙ', '(yaitu) buah-buahan. Mereka adalah orang-orang yang dimuliakan', '', 'https://everyayah.com/data/Alafasy_128kbps/037042.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:43', 37, 43, 23, 447, 3831, 'فِيْ جَنّٰتِ النَّعِيْمِۙ', 'di dalam surga-surga yang penuh kenikmatan.', '', 'https://everyayah.com/data/Alafasy_128kbps/037043.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:44', 37, 44, 23, 447, 3832, 'عَلٰى سُرُرٍ مُّتَقٰبِلِيْنَ', '(Mereka duduk) berhadap-hadapan di atas dipan-dipan.', '', 'https://everyayah.com/data/Alafasy_128kbps/037044.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:45', 37, 45, 23, 447, 3833, 'يُطَافُ عَلَيْهِمْ بِكَأْسٍ مِّنْ مَّعِيْنٍۢ ۙ', 'Kepada mereka diedarkan gelas (yang berisi minuman) dari mata air (surga).', '', 'https://everyayah.com/data/Alafasy_128kbps/037045.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:46', 37, 46, 23, 447, 3834, 'بَيْضَاۤءَ لَذَّةٍ لِّلشّٰرِبِيْنَۚ ', '(Warnanya) putih bersih dan lezat rasanya bagi orang-orang yang meminum(-nya).', '', 'https://everyayah.com/data/Alafasy_128kbps/037046.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:47', 37, 47, 23, 447, 3835, 'لَا فِيْهَا غَوْلٌ وَّلَا هُمْ عَنْهَا يُنْزَفُوْنَ', 'Tidak ada di dalamnya (unsur) yang membahayakan dan mereka tidak mabuk karenanya.', '', 'https://everyayah.com/data/Alafasy_128kbps/037047.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:48', 37, 48, 23, 447, 3836, 'وَعِنْدَهُمْ قٰصِرٰتُ الطَّرْفِ عِيْنٌ ۙ', 'Di sisi mereka ada (bidadari-bidadari) yang bermata indah dan membatasi pandangannya (dari selain pasangan mereka).', '', 'https://everyayah.com/data/Alafasy_128kbps/037048.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:49', 37, 49, 23, 447, 3837, 'كَاَنَّهُنَّ بَيْضٌ مَّكْنُوْنٌ', '(Warna kulit) mereka seperti (warna) telur yang tersimpan dengan baik.', '', 'https://everyayah.com/data/Alafasy_128kbps/037049.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:50', 37, 50, 23, 447, 3838, 'فَاَقْبَلَ بَعْضُهُمْ عَلٰى بَعْضٍ يَّتَسَاۤءَلُوْنَ', 'Mereka berhadap-hadapan satu sama lain sambil bercakap-cakap.', '', 'https://everyayah.com/data/Alafasy_128kbps/037050.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:51', 37, 51, 23, 447, 3839, 'قَالَ قَاۤىِٕلٌ مِّنْهُمْ اِنِّيْ كَانَ لِيْ قَرِيْنٌۙ', 'Berkatalah salah seorang di antara mereka, “Sesungguhnya aku dahulu (di dunia) pernah mempunyai seorang teman', '', 'https://everyayah.com/data/Alafasy_128kbps/037051.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:52', 37, 52, 23, 448, 3840, 'يَّقُوْلُ اَءِنَّكَ لَمِنَ الْمُصَدِّقِيْنَ', 'yang berkata, ‘Apakah sesungguhnya kamu termasuk orang-orang yang membenarkan (hari Kebangkitan)?', '', 'https://everyayah.com/data/Alafasy_128kbps/037052.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:53', 37, 53, 23, 448, 3841, 'ءَاِذَا مِتْنَا وَكُنَّا تُرَابًا وَّعِظَامًا ءَاِنَّا لَمَدِيْنُوْنَ', 'Apabila kami telah mati (lalu) menjadi tanah dan tulang-belulang, apakah kami benar-benar (akan dibangkitkan untuk) diberi balasan?’”', '', 'https://everyayah.com/data/Alafasy_128kbps/037053.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:54', 37, 54, 23, 448, 3842, 'قَالَ هَلْ اَنْتُمْ مُّطَّلِعُوْنَ', 'Dia berkata, “Maukah kamu menengok (temanku itu)?”', '', 'https://everyayah.com/data/Alafasy_128kbps/037054.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:55', 37, 55, 23, 448, 3843, 'فَاطَّلَعَ فَرَاٰهُ فِيْ سَوَاۤءِ الْجَحِيْمِ', 'Maka, dia menengoknya. Lalu, dia melihat (teman)-nya itu di tengah-tengah (neraka) Jahim.', '', 'https://everyayah.com/data/Alafasy_128kbps/037055.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:56', 37, 56, 23, 448, 3844, 'قَالَ تَاللّٰهِ اِنْ كِدْتَّ لَتُرْدِيْنِ ۙ', 'Dia berkata, “Demi Allah, engkau hampir saja mencelakakanku.', '', 'https://everyayah.com/data/Alafasy_128kbps/037056.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:57', 37, 57, 23, 448, 3845, 'وَلَوْلَا نِعْمَةُ رَبِّيْ لَكُنْتُ مِنَ الْمُحْضَرِيْنَ', 'Sekiranya bukan karena nikmat Tuhanku, pastilah aku termasuk orang-orang yang diseret (ke neraka).', '', 'https://everyayah.com/data/Alafasy_128kbps/037057.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:58', 37, 58, 23, 448, 3846, 'اَفَمَا نَحْنُ بِمَيِّتِيْنَۙ', 'Apakah kita tidak akan mati,', '', 'https://everyayah.com/data/Alafasy_128kbps/037058.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:59', 37, 59, 23, 448, 3847, 'اِلَّا مَوْتَتَنَا الْاُوْلٰى وَمَا نَحْنُ بِمُعَذَّبِيْنَ', 'kecuali kematian kita yang pertama saja (di dunia) dan kita tidak akan diazab (di akhirat ini)?”', '', 'https://everyayah.com/data/Alafasy_128kbps/037059.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:60', 37, 60, 23, 448, 3848, 'اِنَّ هٰذَا لَهُوَ الْفَوْزُ الْعَظِيْمُ', 'Sesungguhnya ini benar-benar kemenangan yang agung.', '', 'https://everyayah.com/data/Alafasy_128kbps/037060.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:61', 37, 61, 23, 448, 3849, 'لِمِثْلِ هٰذَا فَلْيَعْمَلِ الْعٰمِلُوْنَ', 'Untuk (kemenangan) seperti ini, hendaklah beramal (di dunia) orang-orang yang mampu beramal.', '', 'https://everyayah.com/data/Alafasy_128kbps/037061.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:62', 37, 62, 23, 448, 3850, 'اَذٰلِكَ خَيْرٌ نُّزُلًا اَمْ شَجَرَةُ الزَّقُّوْمِ', 'Apakah (makanan surga) itu hidangan yang lebih baik ataukah pohon zaqum?', '', 'https://everyayah.com/data/Alafasy_128kbps/037062.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:63', 37, 63, 23, 448, 3851, 'اِنَّا جَعَلْنٰهَا فِتْنَةً لِّلظّٰلِمِيْنَ', 'Sesungguhnya Kami menjadikannya (pohon zaqum itu) sebagai azab bagi orang-orang zalim.', '', 'https://everyayah.com/data/Alafasy_128kbps/037063.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:64', 37, 64, 23, 448, 3852, 'اِنَّهَا شَجَرَةٌ تَخْرُجُ فِيْٓ اَصْلِ الْجَحِيْمِۙ', 'Sesungguhnya itu adalah pohon yang keluar dari dasar (neraka) Jahim.', '', 'https://everyayah.com/data/Alafasy_128kbps/037064.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:65', 37, 65, 23, 448, 3853, 'طَلْعُهَا كَاَنَّهٗ رُءُوْسُ الشَّيٰطِيْنِ', 'Mayangnya seperti kepala-kepala setan.', '', 'https://everyayah.com/data/Alafasy_128kbps/037065.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:66', 37, 66, 23, 448, 3854, 'فَاِنَّهُمْ لَاٰكِلُوْنَ مِنْهَا فَمَالِـُٔوْنَ مِنْهَا الْبُطُوْنَۗ ', 'Sesungguhnya mereka benar-benar memakan sebagian darinya (buah pohon itu) dan mereka memenuhi perutnya dengan buahnya (zaqum).', '', 'https://everyayah.com/data/Alafasy_128kbps/037066.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:67', 37, 67, 23, 448, 3855, 'ثُمَّ اِنَّ لَهُمْ عَلَيْهَا لَشَوْبًا مِّنْ حَمِيْمٍۚ ', '(Setelah makan buah zaqum,) sesungguhnya bagi mereka minuman yang dicampur dengan air yang sangat panas.', '', 'https://everyayah.com/data/Alafasy_128kbps/037067.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:68', 37, 68, 23, 448, 3856, 'ثُمَّ اِنَّ مَرْجِعَهُمْ لَاِلَى الْجَحِيْمِ', 'Kemudian, tempat kembali mereka pasti ke (neraka) Jahim.', '', 'https://everyayah.com/data/Alafasy_128kbps/037068.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:69', 37, 69, 23, 448, 3857, 'اِنَّهُمْ اَلْفَوْا اٰبَاۤءَهُمْ ضَاۤلِّيْنَۙ', 'Sesungguhnya mereka mendapati nenek moyang mereka dalam keadaan sesat.', '', 'https://everyayah.com/data/Alafasy_128kbps/037069.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:70', 37, 70, 23, 448, 3858, 'فَهُمْ عَلٰٓى اٰثٰرِهِمْ يُهْرَعُوْنَ', 'Mereka tergesa-gesa mengikuti jejak (nenek moyang) mereka.', '', 'https://everyayah.com/data/Alafasy_128kbps/037070.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:71', 37, 71, 23, 448, 3859, 'وَلَقَدْ ضَلَّ قَبْلَهُمْ اَكْثَرُ الْاَوَّلِيْنَۙ', 'Sungguh, sebelum mereka (kaum Quraisy), benar-benar telah sesat sebagian besar dari orang-orang yang dahulu.', '', 'https://everyayah.com/data/Alafasy_128kbps/037071.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:72', 37, 72, 23, 448, 3860, 'وَلَقَدْ اَرْسَلْنَا فِيْهِمْ مُّنْذِرِيْنَ', 'Sungguh, Kami benar-benar telah mengutus (rasul) pemberi peringatan di kalangan mereka.', '', 'https://everyayah.com/data/Alafasy_128kbps/037072.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:73', 37, 73, 23, 448, 3861, 'فَانْظُرْ كَيْفَ كَانَ عَاقِبَةُ الْمُنْذَرِيْنَۙ', 'Maka, perhatikanlah bagaimana kesudahan orang-orang yang diberi peringatan itu,', '', 'https://everyayah.com/data/Alafasy_128kbps/037073.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:74', 37, 74, 23, 448, 3862, 'اِلَّا عِبَادَ اللّٰهِ الْمُخْلَصِيْنَ ࣖ ', 'kecuali hamba-hamba Allah yang terpilih (karena keikhlasannya).', '', 'https://everyayah.com/data/Alafasy_128kbps/037074.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:75', 37, 75, 23, 448, 3863, 'وَلَقَدْ نَادٰىنَا نُوْحٌ فَلَنِعْمَ الْمُجِيْبُوْنَۖ ', 'Sungguh, Nuh benar-benar telah berdoa kepada Kami dan sungguh, Kamilah sebaik-baik yang memperkenankan doa.', '', 'https://everyayah.com/data/Alafasy_128kbps/037075.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:76', 37, 76, 23, 448, 3864, 'وَنَجَّيْنٰهُ وَاَهْلَهٗ مِنَ الْكَرْبِ الْعَظِيْمِۖ ', 'Kami telah menyelamatkan dia dan pengikutnya dari bencana yang besar.', '', 'https://everyayah.com/data/Alafasy_128kbps/037076.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:77', 37, 77, 23, 449, 3865, 'وَجَعَلْنَا ذُرِّيَّتَهٗ هُمُ الْبَاقِيْنَ', 'Kami menjadikan keturunannya orang-orang yang bertahan (di bumi).', '', 'https://everyayah.com/data/Alafasy_128kbps/037077.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:78', 37, 78, 23, 449, 3866, 'وَتَرَكْنَا عَلَيْهِ فِى الْاٰخِرِيْنَ ۖ ', 'Kami mengabadikan untuknya (pujian) pada orang-orang yang datang kemudian,', '', 'https://everyayah.com/data/Alafasy_128kbps/037078.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:79', 37, 79, 23, 449, 3867, 'سَلٰمٌ عَلٰى نُوْحٍ فِى الْعٰلَمِيْنَ', '“Kesejahteraan (Kami limpahkan) atas Nuh di semesta alam.”', '', 'https://everyayah.com/data/Alafasy_128kbps/037079.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:80', 37, 80, 23, 449, 3868, 'اِنَّا كَذٰلِكَ نَجْزِى الْمُحْسِنِيْنَ', 'Sesungguhnya, demikianlah Kami memberi balasan kepada orang-orang yang berbuat kebaikan.', '', 'https://everyayah.com/data/Alafasy_128kbps/037080.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:81', 37, 81, 23, 449, 3869, 'اِنَّهٗ مِنْ عِبَادِنَا الْمُؤْمِنِيْنَ', 'Sesungguhnya dia termasuk hamba-hamba Kami yang mukmin.', '', 'https://everyayah.com/data/Alafasy_128kbps/037081.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:82', 37, 82, 23, 449, 3870, 'ثُمَّ اَغْرَقْنَا الْاٰخَرِيْنَ', 'Kemudian, Kami menenggelamkan yang lain.', '', 'https://everyayah.com/data/Alafasy_128kbps/037082.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:83', 37, 83, 23, 449, 3871, '۞ وَاِنَّ مِنْ شِيْعَتِهٖ لَاِبْرٰهِيْمَ ۘ ', 'Sesungguhnya Ibrahim termasuk golongannya (Nuh).646)', '646) Maksudnya, keduanya mempunyai kesamaan dalam hal keimanan kepada Allah Swt. dan pokok-pokok ajaran agama.', 'https://everyayah.com/data/Alafasy_128kbps/037083.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:84', 37, 84, 23, 449, 3872, 'اِذْ جَاۤءَ رَبَّهٗ بِقَلْبٍ سَلِيْمٍۙ', '(Ingatlah) ketika dia datang kepada Tuhannya dengan hati yang suci,647)', '647) Mengikhlaskan hatinya kepada Allah dengan sepenuhnya.', 'https://everyayah.com/data/Alafasy_128kbps/037084.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:85', 37, 85, 23, 449, 3873, 'اِذْ قَالَ لِاَبِيْهِ وَقَوْمِهٖ مَاذَا تَعْبُدُوْنَ ۚ ', 'ketika dia berkata kepada ayahnya dan kaumnya, “Apa yang kamu sembah itu?', '', 'https://everyayah.com/data/Alafasy_128kbps/037085.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:86', 37, 86, 23, 449, 3874, 'اَىِٕفْكًا اٰلِهَةً دُوْنَ اللّٰهِ تُرِيْدُوْنَۗ ', 'Apakah kamu menghendaki kebohongan dengan sesembahan selain Allah?', '', 'https://everyayah.com/data/Alafasy_128kbps/037086.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:87', 37, 87, 23, 449, 3875, 'فَمَا ظَنُّكُمْ بِرَبِّ الْعٰلَمِيْنَ', 'Maka, bagaimana anggapanmu terhadap Tuhan semesta alam?”', '', 'https://everyayah.com/data/Alafasy_128kbps/037087.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:88', 37, 88, 23, 449, 3876, 'فَنَظَرَ نَظْرَةً فِى النُّجُوْمِۙ', 'Lalu, dia (Ibrahim) memandang sekilas ke arah bintang-bintang,', '', 'https://everyayah.com/data/Alafasy_128kbps/037088.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:89', 37, 89, 23, 449, 3877, 'فَقَالَ اِنِّيْ سَقِيْمٌ', 'kemudian dia berkata, “Sesungguhnya aku sakit.”', '', 'https://everyayah.com/data/Alafasy_128kbps/037089.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:90', 37, 90, 23, 449, 3878, 'فَتَوَلَّوْا عَنْهُ مُدْبِرِيْنَ', 'Mereka lalu berpaling darinya seraya meninggalkannya.', '', 'https://everyayah.com/data/Alafasy_128kbps/037090.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:91', 37, 91, 23, 449, 3879, 'فَرَاغَ اِلٰٓى اٰلِهَتِهِمْ فَقَالَ اَلَا تَأْكُلُوْنَۚ ', 'Kemudian, dia langsung menuju ke berhala-berhala mereka (secara diam-diam), lalu berkata, “Mengapa kamu tidak makan?648)', '648) Pertanyaan tersebut diajukan sebagai ejekan pada berhala-berhala yang diberi sajian makanan, tetapi tidak bisa memakannya.', 'https://everyayah.com/data/Alafasy_128kbps/037091.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:92', 37, 92, 23, 449, 3880, 'مَا لَكُمْ لَا تَنْطِقُوْنَ', 'Mengapa kamu tidak menjawab?”', '', 'https://everyayah.com/data/Alafasy_128kbps/037092.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:93', 37, 93, 23, 449, 3881, 'فَرَاغَ عَلَيْهِمْ ضَرْبًا ۢبِالْيَمِيْنِ', 'Dia lalu menghadap ke (berhala-berhala) itu sambil memukul dengan tangan kanan(-nya).', '', 'https://everyayah.com/data/Alafasy_128kbps/037093.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:94', 37, 94, 23, 449, 3882, 'فَاَقْبَلُوْٓا اِلَيْهِ يَزِفُّوْنَ', 'Kemudian, mereka (kaumnya) datang bergegas kepadanya.', '', 'https://everyayah.com/data/Alafasy_128kbps/037094.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:95', 37, 95, 23, 449, 3883, 'قَالَ اَتَعْبُدُوْنَ مَا تَنْحِتُوْنَۙ', 'Dia (Ibrahim) berkata, “Apakah kamu menyembah patung-patung yang kamu pahat itu?', '', 'https://everyayah.com/data/Alafasy_128kbps/037095.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:96', 37, 96, 23, 449, 3884, 'وَاللّٰهُ خَلَقَكُمْ وَمَا تَعْمَلُوْنَ', 'Padahal Allahlah yang menciptakanmu dan apa yang kamu perbuat itu.”', '', 'https://everyayah.com/data/Alafasy_128kbps/037096.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:97', 37, 97, 23, 449, 3885, 'قَالُوا ابْنُوْا لَهٗ بُنْيَانًا فَاَلْقُوْهُ فِى الْجَحِيْمِ', 'Mereka berkata, “Buatlah bangunan (perapian) untuk (membakar)-nya, lalu lemparkan dia ke dalam api yang menyala-nyala itu.”', '', 'https://everyayah.com/data/Alafasy_128kbps/037097.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:98', 37, 98, 23, 449, 3886, 'فَاَرَادُوْا بِهٖ كَيْدًا فَجَعَلْنٰهُمُ الْاَسْفَلِيْنَ', 'Mereka bermaksud memperdayainya, (namun Allah menyelamatkannya), lalu Kami menjadikan mereka orang-orang yang hina.', '', 'https://everyayah.com/data/Alafasy_128kbps/037098.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:99', 37, 99, 23, 449, 3887, 'وَقَالَ اِنِّيْ ذَاهِبٌ اِلٰى رَبِّيْ سَيَهْدِيْنِ', 'Dia (Ibrahim) berkata, “Sesungguhnya aku akan pergi (menghadap) kepada Tuhanku.649) Dia akan memberiku petunjuk.”', '649) Nabi Ibrahim a.s. pergi ke suatu negeri agar dapat menyembah Allah dan berdakwah.', 'https://everyayah.com/data/Alafasy_128kbps/037099.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:100', 37, 100, 23, 449, 3888, 'رَبِّ هَبْ لِيْ مِنَ الصّٰلِحِيْنَ', '100. (Ibrahim berdoa,) “Ya Tuhanku, anugerahkanlah kepadaku (keturunan) yang termasuk orang-orang saleh.”', '', 'https://everyayah.com/data/Alafasy_128kbps/037100.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:101', 37, 101, 23, 449, 3889, 'فَبَشَّرْنٰهُ بِغُلٰمٍ حَلِيْمٍ', 'Maka, Kami memberi kabar gembira kepadanya dengan (kelahiran) seorang anak (Ismail) yang sangat santun.', '', 'https://everyayah.com/data/Alafasy_128kbps/037101.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:102', 37, 102, 23, 449, 3890, 'فَلَمَّا بَلَغَ مَعَهُ السَّعْيَ قَالَ يٰبُنَيَّ اِنِّيْٓ اَرٰى فِى الْمَنَامِ اَنِّيْٓ اَذْبَحُكَ فَانْظُرْ مَاذَا تَرٰىۗ قَالَ يٰٓاَبَتِ افْعَلْ مَا تُؤْمَرُۖ سَتَجِدُنِيْٓ اِنْ شَاۤءَ اللّٰهُ مِنَ الصّٰبِرِيْنَ', 'Ketika anak itu sampai pada (umur) ia sanggup bekerja bersamanya, ia (Ibrahim) berkata, “Wahai anakku, sesungguhnya aku bermimpi bahwa aku menyembelihmu. Pikirkanlah apa pendapatmu?” Dia (Ismail) menjawab, “Wahai ayahku, lakukanlah apa yang diperintahkan (Allah) kepadamu! Insyaallah engkau akan mendapatiku termasuk orang-orang sabar.”', '', 'https://everyayah.com/data/Alafasy_128kbps/037102.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:103', 37, 103, 23, 450, 3891, 'فَلَمَّآ اَسْلَمَا وَتَلَّهٗ لِلْجَبِيْنِۚ ', 'Ketika keduanya telah berserah diri dan dia (Ibrahim) meletakkan pelipis anaknya di atas gundukan (untuk melaksanakan perintah Allah),', '', 'https://everyayah.com/data/Alafasy_128kbps/037103.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:104', 37, 104, 23, 450, 3892, 'وَنَادَيْنٰهُ اَنْ يّٰٓاِبْرٰهِيْمُ ۙ', 'Kami memanggil dia, “Wahai Ibrahim,', '', 'https://everyayah.com/data/Alafasy_128kbps/037104.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:105', 37, 105, 23, 450, 3893, 'قَدْ صَدَّقْتَ الرُّءْيَا ۚاِنَّا كَذٰلِكَ نَجْزِى الْمُحْسِنِيْنَ', 'sungguh, engkau telah membenarkan mimpi itu.” Sesungguhnya demikianlah Kami memberi balasan kepada orang-orang yang berbuat kebaikan.', '', 'https://everyayah.com/data/Alafasy_128kbps/037105.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:106', 37, 106, 23, 450, 3894, 'اِنَّ هٰذَا لَهُوَ الْبَلٰۤؤُا الْمُبِيْنُ', 'Sesungguhnya ini benar-benar suatu ujian yang nyata.', '', 'https://everyayah.com/data/Alafasy_128kbps/037106.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:107', 37, 107, 23, 450, 3895, 'وَفَدَيْنٰهُ بِذِبْحٍ عَظِيْمٍ', 'Kami menebusnya dengan seekor (hewan) sembelihan yang besar.650)', '650) Peristiwa itu menjadi dasar disyariatkannya penyembelihan hewan kurban pada hari raya Iduladha. ', 'https://everyayah.com/data/Alafasy_128kbps/037107.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:108', 37, 108, 23, 450, 3896, 'وَتَرَكْنَا عَلَيْهِ فِى الْاٰخِرِيْنَ ۖ ', 'Kami mengabadikan untuknya (pujian) pada orang-orang yang datang kemudian,', '', 'https://everyayah.com/data/Alafasy_128kbps/037108.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:109', 37, 109, 23, 450, 3897, 'سَلٰمٌ عَلٰٓى اِبْرٰهِيْمَ', '“Salam sejahtera atas Ibrahim.”', '', 'https://everyayah.com/data/Alafasy_128kbps/037109.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:110', 37, 110, 23, 450, 3898, 'كَذٰلِكَ نَجْزِى الْمُحْسِنِيْنَ', 'Demikianlah Kami memberi balasan kepada orang-orang yang berbuat kebaikan.', '', 'https://everyayah.com/data/Alafasy_128kbps/037110.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:111', 37, 111, 23, 450, 3899, 'اِنَّهٗ مِنْ عِبَادِنَا الْمُؤْمِنِيْنَ', 'Sesungguhnya dia termasuk hamba-hamba Kami yang mukmin.', '', 'https://everyayah.com/data/Alafasy_128kbps/037111.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:112', 37, 112, 23, 450, 3900, 'وَبَشَّرْنٰهُ بِاِسْحٰقَ نَبِيًّا مِّنَ الصّٰلِحِيْنَ', 'Kami telah memberinya kabar gembira tentang (akan dilahirkannya) Ishaq, seorang nabi yang termasuk orang-orang saleh.', '', 'https://everyayah.com/data/Alafasy_128kbps/037112.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:113', 37, 113, 23, 450, 3901, 'وَبٰرَكْنَا عَلَيْهِ وَعَلٰٓى اِسْحٰقَۗ وَمِنْ ذُرِّيَّتِهِمَا مُحْسِنٌ وَّظَالِمٌ لِّنَفْسِهٖ مُبِيْنٌ ࣖ', 'Kami melimpahkan keberkahan kepadanya dan Ishaq. Sebagian keturunan keduanya ada yang berbuat baik dan ada (pula) yang terang-terangan berbuat zalim terhadap dirinya sendiri.', '', 'https://everyayah.com/data/Alafasy_128kbps/037113.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:114', 37, 114, 23, 450, 3902, 'وَلَقَدْ مَنَنَّا عَلٰى مُوْسٰى وَهٰرُوْنَ ۚ ', 'Sungguh, Kami benar-benar telah melimpahkan nikmat kepada Musa dan Harun.', '', 'https://everyayah.com/data/Alafasy_128kbps/037114.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:115', 37, 115, 23, 450, 3903, 'وَنَجَّيْنٰهُمَا وَقَوْمَهُمَا مِنَ الْكَرْبِ الْعَظِيْمِۚ ', 'Kami telah menyelamatkan keduanya dan kaumnya dari bencana yang besar.', '', 'https://everyayah.com/data/Alafasy_128kbps/037115.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:116', 37, 116, 23, 450, 3904, 'وَنَصَرْنٰهُمْ فَكَانُوْا هُمُ الْغٰلِبِيْنَۚ ', 'Kami telah menolong mereka sehingga mereka menjadi orang-orang yang menang.', '', 'https://everyayah.com/data/Alafasy_128kbps/037116.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:117', 37, 117, 23, 450, 3905, 'وَاٰتَيْنٰهُمَا الْكِتٰبَ الْمُسْتَبِيْنَ ۚ ', 'Kami telah menganugerahkan kepada keduanya Kitab yang sangat jelas (Taurat).', '', 'https://everyayah.com/data/Alafasy_128kbps/037117.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:118', 37, 118, 23, 450, 3906, 'وَهَدَيْنٰهُمَا الصِّرَاطَ الْمُسْتَقِيْمَۚ ', 'Kami telah membimbing keduanya ke jalan yang lurus.', '', 'https://everyayah.com/data/Alafasy_128kbps/037118.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:119', 37, 119, 23, 450, 3907, 'وَتَرَكْنَا عَلَيْهِمَا فِى الْاٰخِرِيْنَ ۖ ', 'Kami telah mengabadikan untuk keduanya (pujian) pada orang-orang yang datang kemudian,', '', 'https://everyayah.com/data/Alafasy_128kbps/037119.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:120', 37, 120, 23, 450, 3908, 'سَلٰمٌ عَلٰى مُوْسٰى وَهٰرُوْنَ', '“Salam sejahtera atas Musa dan Harun.”', '', 'https://everyayah.com/data/Alafasy_128kbps/037120.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:121', 37, 121, 23, 450, 3909, 'اِنَّا كَذٰلِكَ نَجْزِى الْمُحْسِنِيْنَ', 'Sesungguhnya, demikianlah Kami memberi balasan kepada orang-orang yang berbuat kebaikan.', '', 'https://everyayah.com/data/Alafasy_128kbps/037121.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:122', 37, 122, 23, 450, 3910, 'اِنَّهُمَا مِنْ عِبَادِنَا الْمُؤْمِنِيْنَ', 'Sesungguhnya keduanya termasuk hamba-hamba Kami yang mukmin.', '', 'https://everyayah.com/data/Alafasy_128kbps/037122.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:123', 37, 123, 23, 450, 3911, 'وَاِنَّ اِلْيَاسَ لَمِنَ الْمُرْسَلِيْنَۗ ', 'Sesungguhnya Ilyas benar-benar termasuk para rasul.', '', 'https://everyayah.com/data/Alafasy_128kbps/037123.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:124', 37, 124, 23, 450, 3912, 'اِذْ قَالَ لِقَوْمِهٖٓ اَلَا تَتَّقُوْنَ', '(Ingatlah) ketika dia berkata kepada kaumnya, “Mengapa kamu tidak bertakwa?', '', 'https://everyayah.com/data/Alafasy_128kbps/037124.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:125', 37, 125, 23, 450, 3913, 'اَتَدْعُوْنَ بَعْلًا وَّتَذَرُوْنَ اَحْسَنَ الْخٰلِقِيْنَۙ', 'Apakah kamu terus menyeru Ba‘l651) dan meninggalkan sebaik-baik pencipta,', '651) Ba‘l adalah nama salah satu berhala bangsa Fenisia yang hidup di wilayah yang saat ini menjadi negara Lebanon dan Suriah.', 'https://everyayah.com/data/Alafasy_128kbps/037125.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:126', 37, 126, 23, 450, 3914, 'اللّٰهَ رَبَّكُمْ وَرَبَّ اٰبَاۤىِٕكُمُ الْاَوَّلِيْنَ', 'Allah Tuhanmu dan Tuhan nenek moyangmu yang terdahulu?”', '', 'https://everyayah.com/data/Alafasy_128kbps/037126.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:127', 37, 127, 23, 451, 3915, 'فَكَذَّبُوْهُ فَاِنَّهُمْ لَمُحْضَرُوْنَۙ', 'Mereka kemudian mendustakannya (Ilyas). Sesungguhnya mereka akan diseret (ke neraka),', '', 'https://everyayah.com/data/Alafasy_128kbps/037127.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:128', 37, 128, 23, 451, 3916, 'اِلَّا عِبَادَ اللّٰهِ الْمُخْلَصِيْنَ', 'kecuali hamba-hamba Allah yang terpilih (karena keikhlasannya).', '', 'https://everyayah.com/data/Alafasy_128kbps/037128.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:129', 37, 129, 23, 451, 3917, 'وَتَرَكْنَا عَلَيْهِ فِى الْاٰخِرِيْنَ ۙ', 'Kami mengabadikan untuknya (pujian) pada orang-orang yang datang kemudian,', '', 'https://everyayah.com/data/Alafasy_128kbps/037129.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:130', 37, 130, 23, 451, 3918, 'سَلٰمٌ عَلٰٓى اِلْ يَاسِيْنَ', '“Salam sejahtera atas Ilyas dan kaumnya.”', '', 'https://everyayah.com/data/Alafasy_128kbps/037130.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:131', 37, 131, 23, 451, 3919, 'اِنَّا كَذٰلِكَ نَجْزِى الْمُحْسِنِيْنَ', 'Sesungguhnya, demikianlah Kami memberi balasan kepada orang-orang yang berbuat kebaikan.', '', 'https://everyayah.com/data/Alafasy_128kbps/037131.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:132', 37, 132, 23, 451, 3920, 'اِنَّهٗ مِنْ عِبَادِنَا الْمُؤْمِنِيْنَ', 'Sesungguhnya dia termasuk hamba-hamba Kami yang mukmin.', '', 'https://everyayah.com/data/Alafasy_128kbps/037132.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:133', 37, 133, 23, 451, 3921, 'وَاِنَّ لُوْطًا لَّمِنَ الْمُرْسَلِيْنَۗ ', 'Sesungguhnya Lut benar-benar termasuk para rasul.', '', 'https://everyayah.com/data/Alafasy_128kbps/037133.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:134', 37, 134, 23, 451, 3922, 'اِذْ نَجَّيْنٰهُ وَاَهْلَهٗٓ اَجْمَعِيْنَۙ', '(Ingatlah) ketika Kami telah menyelamatkan dia dan pengikutnya semua,', '', 'https://everyayah.com/data/Alafasy_128kbps/037134.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:135', 37, 135, 23, 451, 3923, 'اِلَّا عَجُوْزًا فِى الْغٰبِرِيْنَ', 'kecuali seorang perempuan tua (istrinya) yang termasuk golongan (orang-orang kafir) yang tertinggal.', '', 'https://everyayah.com/data/Alafasy_128kbps/037135.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:136', 37, 136, 23, 451, 3924, 'ثُمَّ دَمَّرْنَا الْاٰخَرِيْنَ', 'Kemudian, Kami binasakan yang lain.652)', '652) Yaitu mereka yang tetap tinggal di kota dan tidak ikut pergi bersama Nabi Lut a.s.', 'https://everyayah.com/data/Alafasy_128kbps/037136.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:137', 37, 137, 23, 451, 3925, 'وَاِنَّكُمْ لَتَمُرُّوْنَ عَلَيْهِمْ مُّصْبِحِيْنَۙ', 'Sesungguhnya kamu (penduduk Makkah) benar-benar akan melintasi (bekas-bekas kehancuran) mereka pada waktu pagi', '', 'https://everyayah.com/data/Alafasy_128kbps/037137.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:138', 37, 138, 23, 451, 3926, 'وَبِالَّيْلِۗ اَفَلَا تَعْقِلُوْنَ ࣖ ', 'dan waktu malam. Mengapa kamu tidak mengerti?', '', 'https://everyayah.com/data/Alafasy_128kbps/037138.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:139', 37, 139, 23, 451, 3927, 'وَاِنَّ يُوْنُسَ لَمِنَ الْمُرْسَلِيْنَۗ ', 'Sesungguhnya Yunus benar-benar termasuk para rasul.', '', 'https://everyayah.com/data/Alafasy_128kbps/037139.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:140', 37, 140, 23, 451, 3928, 'اِذْ اَبَقَ اِلَى الْفُلْكِ الْمَشْحُوْنِۙ', '(Ingatlah) ketika dia berlari ke kapal yang penuh muatan,', '', 'https://everyayah.com/data/Alafasy_128kbps/037140.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:141', 37, 141, 23, 451, 3929, 'فَسَاهَمَ فَكَانَ مِنَ الْمُدْحَضِيْنَۚ', 'kemudian dia ikut diundi,653) maka dia termasuk orang-orang yang kalah (dalam undian).', '653) Undian diadakan karena muatan kapal sangat penuh dan dikhawatirkan akan tenggelam jika penumpang tidak dikurangi. Orang yang namanya keluar dalam undian dinyatakan kalah dan akan dilempar ke laut. Nama Nabi Yunus a.s. keluar dalam undian tersebut sehingga dia dilemparkan ke laut.', 'https://everyayah.com/data/Alafasy_128kbps/037141.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:142', 37, 142, 23, 451, 3930, 'فَالْتَقَمَهُ الْحُوْتُ وَهُوَ مُلِيْمٌ ', 'Dia kemudian ditelan oleh ikan besar dalam keadaan tercela.654)', '654) Disebut tercela karena dia lari meninggalkan kaumnya.', 'https://everyayah.com/data/Alafasy_128kbps/037142.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:143', 37, 143, 23, 451, 3931, 'فَلَوْلَآ اَنَّهٗ كَانَ مِنَ الْمُسَبِّحِيْنَ ۙ', 'Seandainya dia bukan golongan orang yang banyak bertasbih kepada Allah,', '', 'https://everyayah.com/data/Alafasy_128kbps/037143.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:144', 37, 144, 23, 451, 3932, 'لَلَبِثَ فِيْ بَطْنِهٖٓ اِلٰى يَوْمِ يُبْعَثُوْنَۚ ', 'niscaya dia akan tetap tinggal di perutnya (ikan) sampai hari Kebangkitan.', '', 'https://everyayah.com/data/Alafasy_128kbps/037144.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:145', 37, 145, 23, 451, 3933, '۞ فَنَبَذْنٰهُ بِالْعَرَاۤءِ وَهُوَ سَقِيْمٌ ۚ ', 'Kami kemudian melemparkannya (dari mulut ikan) ke daratan yang tandus, sedang dia dalam keadaan sakit.', '', 'https://everyayah.com/data/Alafasy_128kbps/037145.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:146', 37, 146, 23, 451, 3934, 'وَاَنْۢبَتْنَا عَلَيْهِ شَجَرَةً مِّنْ يَّقْطِيْنٍۚ ', 'Kami kemudian menumbuhkan tanaman sejenis labu untuknya.', '', 'https://everyayah.com/data/Alafasy_128kbps/037146.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:147', 37, 147, 23, 451, 3935, 'وَاَرْسَلْنٰهُ اِلٰى مِائَةِ اَلْفٍ اَوْ يَزِيْدُوْنَۚ ', 'Kami mengutusnya kepada seratus ribu (orang) atau lebih,', '', 'https://everyayah.com/data/Alafasy_128kbps/037147.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:148', 37, 148, 23, 451, 3936, 'فَاٰمَنُوْا فَمَتَّعْنٰهُمْ اِلٰى حِيْنٍ', 'lalu mereka beriman. Maka, Kami menganugerahkan kenikmatan hidup kepada mereka hingga waktu tertentu.', '', 'https://everyayah.com/data/Alafasy_128kbps/037148.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:149', 37, 149, 23, 451, 3937, 'فَاسْتَفْتِهِمْ اَلِرَبِّكَ الْبَنَاتُ وَلَهُمُ الْبَنُوْنَۚ ', '(Wahai Nabi Muhammad,) tanyalah mereka (orang-orang kafir Makkah), “Apakah untuk Tuhanmu anak-anak perempuan, sedangkan untuk mereka anak-anak laki-laki655)', '655) Orang musyrik Makkah mengatakan bahwa malaikat adalah anak-anak perempuan Allah Swt., padahal mereka sendiri menganggap hina anak perempuan.', 'https://everyayah.com/data/Alafasy_128kbps/037149.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:150', 37, 150, 23, 451, 3938, 'اَمْ خَلَقْنَا الْمَلٰۤىِٕكَةَ اِنَاثًا وَّهُمْ شٰهِدُوْنَ', 'atau Kami menciptakan malaikat-malaikat berupa perempuan, sedangkan mereka menyaksikan(-nya)?”', '', 'https://everyayah.com/data/Alafasy_128kbps/037150.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:151', 37, 151, 23, 451, 3939, 'اَلَآ اِنَّهُمْ مِّنْ اِفْكِهِمْ لَيَقُوْلُوْنَۙ', 'Ingatlah, sesungguhnya mereka benar-benar mengatakan dengan kebohongan mereka,', '', 'https://everyayah.com/data/Alafasy_128kbps/037151.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:152', 37, 152, 23, 451, 3940, 'وَلَدَ اللّٰهُ ۙوَاِنَّهُمْ لَكٰذِبُوْنَۙ', '“Allah mempunyai anak.” Sesungguhnya mereka benar-benar pendusta.', '', 'https://everyayah.com/data/Alafasy_128kbps/037152.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:153', 37, 153, 23, 451, 3941, 'اَصْطَفَى الْبَنَاتِ عَلَى الْبَنِيْنَۗ ', 'Apakah Dia (Allah) lebih memilih anak-anak perempuan daripada anak-anak laki-laki?', '', 'https://everyayah.com/data/Alafasy_128kbps/037153.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:154', 37, 154, 23, 452, 3942, 'مَا لَكُمْۗ  كَيْفَ تَحْكُمُوْنَ', 'Apa yang telah terjadi pada kamu? Bagaimana kamu menetapkan(-nya)?', '', 'https://everyayah.com/data/Alafasy_128kbps/037154.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:155', 37, 155, 23, 452, 3943, 'اَفَلَا تَذَكَّرُوْنَۚ ', 'Maka, mengapa kamu tidak mengambil pelajaran?', '', 'https://everyayah.com/data/Alafasy_128kbps/037155.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:156', 37, 156, 23, 452, 3944, 'اَمْ لَكُمْ سُلْطٰنٌ مُّبِيْنٌۙ', 'Ataukah kamu mempunyai bukti yang jelas?', '', 'https://everyayah.com/data/Alafasy_128kbps/037156.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:157', 37, 157, 23, 452, 3945, 'فَأْتُوْا بِكِتٰبِكُمْ اِنْ كُنْتُمْ صٰدِقِيْنَ', '(Kalau begitu,) bawalah kitabmu jika kamu orang-orang yang benar.', '', 'https://everyayah.com/data/Alafasy_128kbps/037157.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:158', 37, 158, 23, 452, 3946, 'وَجَعَلُوْا بَيْنَهٗ وَبَيْنَ الْجِنَّةِ نَسَبًا ۗوَلَقَدْ عَلِمَتِ الْجِنَّةُ اِنَّهُمْ لَمُحْضَرُوْنَۙ', 'Mereka menjadikan (hubungan) nasab antara Dia dan jin. Sungguh, jin benar-benar telah mengetahui bahwa mereka (kaum musyrik) pasti akan diseret (ke neraka),', '', 'https://everyayah.com/data/Alafasy_128kbps/037158.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:159', 37, 159, 23, 452, 3947, 'سُبْحٰنَ اللّٰهِ عَمَّا يَصِفُوْنَۙ', 'Maha Suci Allah dari apa yang mereka sifatkan,', '', 'https://everyayah.com/data/Alafasy_128kbps/037159.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:160', 37, 160, 23, 452, 3948, 'اِلَّا عِبَادَ اللّٰهِ الْمُخْلَصِيْنَ', 'kecuali hamba-hamba Allah yang terpilih (karena keikhlasannya).', '', 'https://everyayah.com/data/Alafasy_128kbps/037160.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:161', 37, 161, 23, 452, 3949, 'فَاِنَّكُمْ وَمَا تَعْبُدُوْنَۙ', 'Maka, sesungguhnya kamu dan apa yang kamu sembah itu', '', 'https://everyayah.com/data/Alafasy_128kbps/037161.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:162', 37, 162, 23, 452, 3950, 'مَآ اَنْتُمْ عَلَيْهِ بِفٰتِنِيْنَۙ', 'tidak akan dapat menyesatkan (seseorang) terhadap Allah,', '', 'https://everyayah.com/data/Alafasy_128kbps/037162.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:163', 37, 163, 23, 452, 3951, 'اِلَّا مَنْ هُوَ صَالِ الْجَحِيْمِ', 'kecuali orang yang akan masuk ke (neraka) Jahim.', '', 'https://everyayah.com/data/Alafasy_128kbps/037163.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:164', 37, 164, 23, 452, 3952, 'وَمَا مِنَّآ اِلَّا لَهٗ مَقَامٌ مَّعْلُوْمٌۙ', '(Malaikat berkata,) “Tidak satu pun di antara kami, kecuali masing-masing mempunyai kedudukan tertentu.', '', 'https://everyayah.com/data/Alafasy_128kbps/037164.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:165', 37, 165, 23, 452, 3953, 'وَّاِنَّا لَنَحْنُ الصَّۤافُّوْنَۖ', 'Sesungguhnya kamilah yang selalu teratur dalam barisan (dalam melaksanakan perintah Allah).', '', 'https://everyayah.com/data/Alafasy_128kbps/037165.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:166', 37, 166, 23, 452, 3954, 'وَاِنَّا لَنَحْنُ الْمُسَبِّحُوْنَ', 'Sesungguhnya kamilah yang benar-benar terus bertasbih (kepada Allah).”', '', 'https://everyayah.com/data/Alafasy_128kbps/037166.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:167', 37, 167, 23, 452, 3955, 'وَاِنْ كَانُوْا لَيَقُوْلُوْنَۙ', 'Sesungguhnya mereka (orang kafir Makkah) benar-benar berkata,', '', 'https://everyayah.com/data/Alafasy_128kbps/037167.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:168', 37, 168, 23, 452, 3956, 'لَوْ اَنَّ عِنْدَنَا ذِكْرًا مِّنَ الْاَوَّلِيْنَۙ', '“Seandainya di sisi kami ada sebuah kitab dari (kitab-kitab yang diturunkan) kepada orang-orang terdahulu,', '', 'https://everyayah.com/data/Alafasy_128kbps/037168.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:169', 37, 169, 23, 452, 3957, 'لَكُنَّا عِبَادَ اللّٰهِ الْمُخْلَصِيْنَ', 'niscaya kami akan menjadi hamba-hamba Allah yang terpilih.', '', 'https://everyayah.com/data/Alafasy_128kbps/037169.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('37:170', 37, 170, 23, 452, 3958, 'فَكَفَرُوْا بِهٖۚ فَسَوْفَ يَعْلَمُوْنَ', 'Akan tetapi, ternyata mereka mengingkarinya (Al-Qur’an). Maka, kelak mereka akan mengetahui (akibat keingkarannya itu).', '', 'https://everyayah.com/data/Alafasy_128kbps/037170.mp3');
